class Solution {
public:
    int findBestValue(vector<int>& arr, int target) {
        sort(arr.begin(), arr.end());
        int n = arr.size();
        vector<int> prefix(n + 1, 0);
        for (int i = 0; i < n; ++i) {
            prefix[i + 1] = prefix[i] + arr[i];
        }

        int left = 0, right = arr.back();
        int bestVal = 0;
        int minDiff = INT_MAX;

        while (left <= right) {
            int mid = left + (right - left) / 2;
            int idx = upper_bound(arr.begin(), arr.end(), mid) - arr.begin();
            int sum = prefix[idx] + (n - idx) * mid;
            int diff = abs(sum - target);

            if (diff < minDiff || (diff == minDiff && mid < bestVal)) {
                minDiff = diff;
                bestVal = mid;
            }

            if (sum < target) {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }

        return bestVal;
    }
};
```
efficiency: HIGH
time complexity: O(n log n)
space complexity: O(n)
energy implications: LOW
explanation: Sort the array and precompute prefix sums. Binary-search the optimal value, using upper_bound to compute the capped sum in O(log n) per step. The binary search narrows the candidate range efficiently, ensuring minimal comparisons and memory usage.

